        except (json.JSONDecodeError, OSError):
            continue
        summaries.append({
            "filename": filepath.name,
            "name": profile.get("name", "Unknown"),
            "level": profile.get("level", "unknown"),
            "sessionCount": profile.get("sessionCount", 0),
        })

    return json.dumps(summaries, indent=2)


